import React, { useEffect } from 'react';
import { useLocation, useNavigate, Link } from 'react-router-dom';

const Success = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const orderData = location.state || {};

  useEffect(() => {
    if (orderData.squareNumber && orderData.businessName) {
      // Save the purchase to localStorage
      const purchaseData = {
        status: 'active',
        businessName: orderData.businessName,
        logoData: orderData.logoData,
        adText: `Special Deal from ${orderData.businessName}`,
        dealLink: orderData.dealLink,
        contactEmail: orderData.contactEmail,
        startDate: orderData.campaignStartDate || new Date().toISOString(),
        endDate: orderData.campaignEndDate || new Date(Date.now() + (orderData.duration || 10) * 24 * 60 * 60 * 1000).toISOString(),
        originalOrder: orderData
      };

      // Load existing purchases
      const existingPurchases = JSON.parse(localStorage.getItem('squarePurchases') || '{}');
      
      // Add new purchase
      existingPurchases[orderData.squareNumber] = purchaseData;
      
      // Save back to localStorage
      localStorage.setItem('squarePurchases', JSON.stringify(existingPurchases));
      
      // Force refresh all AdGrid components
      localStorage.setItem('purchasesUpdated', Date.now().toString());
    }
  }, [orderData]);

  if (!orderData.squareNumber) {
    return (
      <div className="success-container">
        <div className="success-content">
          <h1>Order Complete! 🎉</h1>
          <p>Your advertising campaign has been successfully set up.</p>
          <Link to="/" className="btn-primary">Return to Home</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="success-container">
      <div className="success-content">
        <div className="success-icon">✅</div>
        <h1>Congratulations! 🎉</h1>
        <p className="success-message">Your advertising campaign is now live!</p>
        
        <div className="order-details">
          <h3>Order Details</h3>
          <div className="detail-item">
            <span>Business Name:</span>
            <strong>{orderData.businessName}</strong>
          </div>
          <div className="detail-item">
            <span>Advertising Square:</span>
            <strong>#{orderData.squareNumber} (Page {orderData.pageNumber})</strong>
          </div>
          <div className="detail-item">
            <span>Campaign Duration:</span>
            <strong>{orderData.duration} days</strong>
          </div>
          <div className="detail-item">
            <span>Total Paid:</span>
            <strong>£{orderData.finalAmount || 0}.00</strong>
          </div>
          {orderData.couponUsed && (
            <div className="detail-item">
              <span>Coupon Used:</span>
              <strong>{orderData.couponUsed.code} ({orderData.couponUsed.discountPercent}% OFF)</strong>
            </div>
          )}
        </div>

        <div className="success-actions">
          <button 
            onClick={() => navigate(`/page${orderData.pageNumber}`)}
            className="btn-primary"
          >
            👁️ View Your Ad
          </button>
          <button 
            onClick={() => navigate('/')}
            className="btn-secondary"
          >
            🏠 Return Home
          </button>
          <button 
            onClick={() => navigate('/purchase')}
            className="btn-secondary"
          >
            📢 Buy Another Ad
          </button>
        </div>

        <div className="success-tips">
          <h4>What happens next?</h4>
          <ul>
            <li>✅ Your ad is live immediately</li>
            <li>👆 Click "View Your Ad" to see it on the grid</li>
            <li>🔗 Visitors can click your square to visit your deal page</li>
            <li>📧 You'll receive email confirmation shortly</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default Success;
